export function getEventImage(event) {
  const imgs = CATEGORY_IMAGES[event.category] || CATEGORY_IMAGES.cultural_fallback
  const idx = (event.id - 1) % imgs.length
  return `https://images.unsplash.com/photo-${imgs[idx]}?w=800&h=450&fit=crop&auto=format&q=80`
}

export function getEventImageThumb(event) {
  const imgs = CATEGORY_IMAGES[event.category] || CATEGORY_IMAGES.cultural_fallback
  const idx = (event.id - 1) % imgs.length
  return `https://images.unsplash.com/photo-${imgs[idx]}?w=400&h=240&fit=crop&auto=format&q=75`
}

